interface Client {
  id: string
  name: string
  contact_name: string | null
  phone: string | null
  email: string | null
  address: string | null
  zone: string | null
  client_type: string
  credit_limit: number
  is_active: boolean
  created_at: string
  product_balance: number
  packaging_balance: number
}

async function getClients(companyId: string): Promise<Client[]> {
  try {
    const clients = await sql`
      SELECT 
        c.*,
        COALESCE(
          (SELECT balance FROM client_accounts ca WHERE ca.client_id = c.id AND ca.account_type = 'product'),
          0
        ) as product_balance,
        COALESCE(
          (SELECT balance FROM client_accounts ca WHERE ca.client_id = c.id AND ca.account_type = 'packaging'),
          0
        ) as packaging_balance
      FROM clients c
      WHERE c.company_id = ${companyId}
      ORDER BY c.name
    `
    return clients as Client[]
  } catch (error) {
    console.error('Error fetching clients:', error)
    return []
  }
}

function formatCurrency(amount: number) {
  return new Intl.NumberFormat('fr-FR', {
    style: 'currency',
    currency: 'XOF',
    minimumFractionDigits: 0,
  }).format(amount)
}

